use hopr_api::types::{internal::errors::CoreTypesError, primitive::errors::GeneralError};
use thiserror::Error;

/// Errors generated by the crate.
#[derive(Error, Debug)]
pub enum ProtocolError {
    #[error("timeout on protocol operation")]
    Timeout,

    #[error(transparent)]
    Other(Box<dyn std::error::Error + Send + Sync + 'static>),

    #[error("General error {0}")]
    GeneralError(#[from] GeneralError),

    #[error("Core error {0}")]
    CoreError(#[from] CoreTypesError),

    #[error("Failed on a logical error: {0}")]
    Logic(String),
}

/// Result used by the crate, based on the [ProtocolError] error type.
pub type Result<T> = core::result::Result<T, ProtocolError>;

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn protocol_error_variants_should_display_correctly() {
        let variants: Vec<String> = vec![
            ProtocolError::Timeout.to_string(),
            ProtocolError::Logic("test logic error".into()).to_string(),
            ProtocolError::GeneralError(GeneralError::ParseError("bad parse".into())).to_string(),
        ];
        insta::assert_debug_snapshot!(variants);
    }
}
